def verify(actual_output, expected_output):
    """Verify the Twitter operations result"""
    def val_to_string(v):
        if v is None:
            return 'null'
        if isinstance(v, list):
            return '[' + ', '.join(str(x) for x in v) + ']'
        return str(v)

    def list_to_string(lst):
        if not lst:
            return '[]'
        return '[' + ', '.join(val_to_string(x) for x in lst) + ']'

    passed = True
    if len(actual_output) != len(expected_output):
        passed = False
    else:
        for actual, expected in zip(actual_output, expected_output):
            if expected is None:
                if actual is not None:
                    passed = False
                    break
            elif isinstance(expected, list):
                if not isinstance(actual, list) or actual != expected:
                    passed = False
                    break
            elif actual != expected:
                passed = False
                break

    return [passed, list_to_string(actual_output)]
